.script-editor-container{display:flex;flex-direction:column;height:100%;background:var(--SmartThemeBlurTintColor);border-radius:6px;overflow:hidden}.editor-header{display:flex;justify-content:space-between;align-items:center;padding:12px 16px;background:rgba(0,0,0,.2);border-bottom:1px solid var(--SmartThemeBorderColor)}.editor-info{display:flex;flex-direction:column;gap:4px}.script-title{margin:0;font-size:16px;font-weight:600;color:var(--SmartThemeEmColor)}.editor-status{display:flex;align-items:center;gap:12px;font-size:12px}.status-indicator{display:flex;align-items:center;gap:4px;color:#888}.status-indicator.dirty{color:#ff9500}.status-indicator.saving{color:#4caf50}.status-indicator i{font-size:10px}.last-saved{color:#666}.editor-actions{display:flex;gap:8px}.save-btn,.format-btn,.run-btn,.info-btn{display:flex;align-items:center;gap:6px;padding:8px 12px;border:1px solid var(--SmartThemeBorderColor);border-radius:4px;background:none;color:var(--SmartThemeBodyColor);cursor:pointer;font-size:12px;transition:all .2s ease}.save-btn:not(:disabled):hover{background:#4caf50;border-color:#4caf50;color:#fff}.run-btn:not(:disabled):hover{background:#2196f3;border-color:#2196f3;color:#fff}.format-btn:not(:disabled):hover{background:#ff9800;border-color:#ff9800;color:#fff}.info-btn:hover,.info-btn.active{background:var(--SmartThemeQuoteColor);border-color:var(--SmartThemeEmColor);color:var(--SmartThemeEmColor)}.save-btn:disabled,.format-btn:disabled,.run-btn:disabled{opacity:.5;cursor:not-allowed}.script-info-panel{padding:16px;background:rgba(0,0,0,.1);border-bottom:1px solid var(--SmartThemeBorderColor)}.info-grid{display:grid;grid-template-columns:1fr 200px;gap:12px}.info-field{display:flex;flex-direction:column;gap:4px}.info-field.full-width{grid-column:1/-1}.info-field label{font-size:12px;font-weight:500;color:var(--SmartThemeEmColor)}.text-input,.text-area{padding:8px;border:1px solid var(--SmartThemeBorderColor);border-radius:4px;background:rgba(0,0,0,.2);color:var(--SmartThemeBodyColor);font-size:13px}.text-input:focus,.text-area:focus{outline:none;border-color:var(--SmartThemeEmColor)}.status-toggle{display:flex;align-items:center;gap:6px;padding:8px 12px;border:1px solid var(--SmartThemeBorderColor);border-radius:4px;background:none;color:#888;cursor:pointer;font-size:12px;transition:all .2s ease}.status-toggle.enabled{color:#4caf50;border-color:#4caf50}.status-toggle:hover{background:hsla(0,0%,100%,.05)}.editor-body{flex:1;display:flex;flex-direction:column;overflow:hidden}.code-editor-container{flex:1;display:flex;flex-direction:column}.code-editor{flex:1;padding:16px;border:none;background:rgba(0,0,0,.2);color:var(--SmartThemeBodyColor);font-family:"Consolas","Monaco","Courier New",monospace;font-size:14px;line-height:1.5;resize:none;outline:none;white-space:pre;overflow-wrap:normal;overflow-x:auto}.code-editor::placeholder{color:#666}.editor-statusbar{display:flex;justify-content:space-between;align-items:center;padding:6px 16px;background:rgba(0,0,0,.3);border-top:1px solid var(--SmartThemeBorderColor);font-size:11px;color:#888}.cursor-position,.editor-mode,.content-stats{display:flex;align-items:center;gap:4px}.empty-editor{flex:1;display:flex;align-items:center;justify-content:center;padding:40px}.empty-content{text-align:center;color:var(--SmartThemeBodyColor)}.empty-content i{font-size:48px;margin-bottom:16px;opacity:.5;color:#666}.empty-content h3{margin:0 0 8px 0;color:var(--SmartThemeEmColor)}.empty-content p{margin:0;opacity:.8}.code-editor::-webkit-scrollbar{width:12px;height:12px}.code-editor::-webkit-scrollbar-track{background:rgba(0,0,0,.1)}.code-editor::-webkit-scrollbar-thumb{background:hsla(0,0%,100%,.2);border-radius:6px}.code-editor::-webkit-scrollbar-thumb:hover{background:hsla(0,0%,100%,.3)}