.script-search-container{position:relative}.text_pole{padding-right:50px}.script-search-icon{position:absolute;right:5px;top:50%;transform:translateY(-50%);color:var(--SmartThemeEmColor);pointer-events:none}.clear-search-btn{position:absolute;right:30px;top:50%;transform:translateY(-50%);background-color:rgba(0,0,0,0);border:none;cursor:pointer;padding:5px;margin:0;color:var(--SmartThemeEmColor);border-radius:50%;display:flex;align-items:center;justify-content:center}.clear-search-btn:hover{color:var(--SmartThemeQuoteColor);background:hsla(0,0%,100%,.1)}.repository-content{position:relative}.loading-overlay{position:absolute;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.5);z-index:10}.loading-spinner{color:#fff}.error-message{background:rgba(255,0,0,.1);border:1px solid rgba(255,0,0,.3);border-radius:4px;color:#ff6b6b}.retry-btn{background:none;border:1px solid currentColor;color:inherit;padding:4px 8px;border-radius:3px;cursor:pointer}.retry-btn:hover{background:rgba(255,107,107,.1)}.repository-stats{color:var(--SmartThemeBodyColor);border-bottom:1px solid var(--SmartThemeBorderColor)}.stats-item{background:rgba(0,0,0,.1);border-radius:3px}.search-stats{color:var(--SmartThemeEmColor);font-weight:500}.view-toggle{background:rgba(0,0,0,.1);border-radius:6px;margin-bottom:12px}.view-btn{border-radius:4px;background:none;color:var(--SmartThemeBodyColor);cursor:pointer;transition:all .2s ease;border:1px solid rgba(0,0,0,0)}.view-btn:hover{background:hsla(0,0%,100%,.05);border-color:var(--SmartThemeBorderColor)}.view-btn.active{background:var(--SmartThemeQuoteColor);color:var(--SmartThemeEmColor);border-color:var(--SmartThemeEmColor)}.left-panel{min-width:300px}.panel-divider{width:4px;background:var(--SmartThemeBorderColor);cursor:col-resize;transition:background .2s ease;position:relative}.panel-divider:hover{background:var(--SmartThemeEmColor)}.panel-divider::after{content:"";position:absolute;left:-2px;right:-2px;top:0;bottom:0}.right-panel{min-width:300px;max-width:800px}