.folder-tree-container{display:flex;flex-direction:column;gap:4px;padding:8px 0}.root-scripts{margin-bottom:8px}.tree-node{display:flex;flex-direction:column}.root-node{background:rgba(0,0,0,.1);border-radius:4px;padding:4px}.node-header{display:flex;justify-content:space-between;align-items:center;padding:6px 8px;cursor:pointer;border-radius:3px;transition:background .2s ease}.node-header:hover{background:hsla(0,0%,100%,.05)}.node-info{display:flex;align-items:center;gap:6px;flex:1}.node-icon{color:var(--SmartThemeEmColor);font-size:14px}.node-name{font-size:13px;font-weight:500;color:var(--SmartThemeEmColor)}.node-count{font-size:11px;color:#888}.expand-btn{background:none;border:none;cursor:pointer;padding:2px;color:#888;transition:all .2s ease;font-size:12px}.expand-btn:hover{color:var(--SmartThemeEmColor)}.expand-btn.expanded{transform:rotate(90deg)}.node-children{margin-left:16px;padding-top:4px;border-left:1px solid hsla(0,0%,100%,.1)}.script-node{display:flex;justify-content:space-between;align-items:center;padding:4px 8px;margin:1px 0;border-radius:3px;cursor:pointer;transition:background .2s ease}.script-node:hover{background:hsla(0,0%,100%,.05)}.script-node.selected{background:rgba(var(--SmartThemeQuoteColor), 0.3);border-left:2px solid var(--SmartThemeEmColor)}.script-info{display:flex;align-items:center;gap:6px;flex:1;min-width:0}.script-enabled{color:#4caf50}.script-disabled{color:#888}.script-name{font-size:12px;color:var(--SmartThemeBodyColor);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.script-actions{display:flex;gap:4px;flex-shrink:0}.toggle-btn{background:none;border:none;cursor:pointer;padding:2px 4px;border-radius:2px;color:#888;transition:all .2s ease;font-size:10px}.toggle-btn:hover{background:hsla(0,0%,100%,.1)}.toggle-btn.enabled{color:#4caf50}.folder-tree{display:flex;flex-direction:column;gap:2px}.empty-tree{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:40px 20px;color:#888;font-size:13px}.empty-tree i{font-size:24px;margin-bottom:8px;opacity:.5}