.toast-container{position:fixed;top:20px;right:20px;z-index:9999;pointer-events:none}.toast{pointer-events:auto;margin-bottom:12px;max-width:400px;min-width:300px;border-radius:6px;box-shadow:0 4px 12px rgba(0,0,0,.3);overflow:hidden;backdrop-filter:blur(8px)}.toast-success{background:linear-gradient(135deg, rgba(76, 175, 80, 0.95), rgba(67, 160, 71, 0.95));border-left:4px solid #4caf50}.toast-error{background:linear-gradient(135deg, rgba(244, 67, 54, 0.95), rgba(229, 57, 53, 0.95));border-left:4px solid #f44336}.toast-warning{background:linear-gradient(135deg, rgba(255, 152, 0, 0.95), rgba(251, 140, 0, 0.95));border-left:4px solid #ff9800}.toast-info{background:linear-gradient(135deg, rgba(33, 150, 243, 0.95), rgba(30, 136, 229, 0.95));border-left:4px solid #2196f3}.toast-content{display:flex;align-items:flex-start;gap:12px;padding:16px;color:#fff}.toast-icon{flex-shrink:0;font-size:18px;margin-top:2px}.toast-body{flex:1;min-width:0}.toast-title{font-weight:600;font-size:14px;margin-bottom:4px}.toast-message{font-size:13px;opacity:.9;line-height:1.4}.toast-actions{display:flex;gap:6px;align-items:flex-start;flex-shrink:0}.toast-action-btn{background:hsla(0,0%,100%,.2);border:1px solid hsla(0,0%,100%,.3);color:#fff;padding:4px 8px;border-radius:3px;font-size:11px;cursor:pointer;transition:all .2s ease}.toast-action-btn:hover{background:hsla(0,0%,100%,.3)}.toast-close-btn{background:none;border:none;color:hsla(0,0%,100%,.8);cursor:pointer;padding:2px;border-radius:2px;font-size:12px;transition:all .2s ease}.toast-close-btn:hover{color:#fff;background:hsla(0,0%,100%,.2)}.toast-enter-active,.toast-leave-active{transition:all .3s ease}.toast-enter-from{opacity:0;transform:translateX(100%)}.toast-leave-to{opacity:0;transform:translateX(100%)}.toast-move{transition:transform .3s ease}