.script-list-container{flex:1;overflow-y:auto;padding-right:4px}.empty-state{display:flex;align-items:center;justify-content:center;height:100%;min-height:200px}.empty-search,.empty-repository{text-align:center;color:var(--SmartThemeBodyColor)}.empty-search i,.empty-repository i{font-size:48px;margin-bottom:15px;opacity:.5}.empty-search h3,.empty-repository h3{margin:10px 0;color:var(--SmartThemeEmColor)}.empty-search p,.empty-repository p{margin-bottom:15px;opacity:.8}.script-list{display:flex;flex-direction:column;gap:8px;padding:4px 0}.script-list-container::-webkit-scrollbar{width:8px}.script-list-container::-webkit-scrollbar-track{background:rgba(0,0,0,.1);border-radius:4px}.script-list-container::-webkit-scrollbar-thumb{background:hsla(0,0%,100%,.2);border-radius:4px}.script-list-container::-webkit-scrollbar-thumb:hover{background:hsla(0,0%,100%,.3)}