.script-item{width:100%;border:1px solid var(--SmartThemeBorderColor);border-radius:10px;min-height:35px;display:flex;justify-content:space-between;flex-wrap:nowrap;align-items:center;padding:0 5px}.script-item.preset-mode{background-color:var(--SmartThemeBlurTintColor)}.script-item-name{text-align:left;transition:all .2s ease}.script-item-name.disabled{text-decoration:line-through;filter:grayscale(0.5)}.script-toggle{cursor:pointer;transition:color .2s ease}.script-toggle:hover{color:var(--SmartThemeQuoteColor)}.script-toggle.enabled .fa-toggle-on{color:var(--green)}.script-toggle:not(.enabled) .fa-toggle-off{color:var(--red)}.menu_button{cursor:pointer;padding:5px;border-radius:3px;transition:background-color .2s ease}.menu_button:hover{background-color:var(--grey20)}.preset-bind-indicator{color:var(--SmartThemeQuoteColor);cursor:default}.preset-bind-indicator:hover{background-color:rgba(0,0,0,0)}.drag-handle{cursor:move;padding:5px;opacity:.6;user-select:none}.drag-handle:hover{opacity:1}.script-item-control{gap:5px}