.folder-tree-node{display:flex;flex-direction:column}.folder-header{display:flex;justify-content:space-between;align-items:center;padding:6px 8px;cursor:pointer;border-radius:4px;transition:background .2s ease;min-height:32px}.folder-header:hover{background:hsla(0,0%,100%,.05)}.folder-info{display:flex;align-items:center;gap:6px;flex:1;min-width:0}.expand-btn{background:none;border:none;cursor:pointer;padding:2px;color:#888;transition:all .2s ease;font-size:12px;width:16px;height:16px;display:flex;align-items:center;justify-content:center}.expand-btn:hover{color:var(--SmartThemeEmColor)}.expand-btn.expanded{transform:rotate(90deg)}.folder-icon{font-size:14px;flex-shrink:0}.folder-name{font-size:13px;font-weight:500;color:var(--SmartThemeEmColor);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.folder-count{font-size:11px;color:#888;flex-shrink:0}.folder-actions{display:flex;gap:4px;flex-shrink:0;opacity:0;transition:opacity .2s ease}.folder-header:hover .folder-actions{opacity:1}.action-btn{background:none;border:1px solid rgba(0,0,0,0);cursor:pointer;padding:4px 6px;border-radius:3px;color:#888;font-size:10px;transition:all .2s ease}.action-btn:hover{background:hsla(0,0%,100%,.1);border-color:var(--SmartThemeBorderColor);color:var(--SmartThemeEmColor)}.folder-content{display:flex;flex-direction:column;margin-left:12px;border-left:1px solid hsla(0,0%,100%,.1);padding-left:4px}.script-node{display:flex;justify-content:space-between;align-items:center;padding:4px 8px;margin:1px 0;border-radius:3px;cursor:pointer;transition:background .2s ease;min-height:28px}.script-node:hover{background:hsla(0,0%,100%,.05)}.script-node.selected{background:var(--SmartThemeQuoteColor);border-left:2px solid var(--SmartThemeEmColor)}.script-info{display:flex;align-items:center;gap:6px;flex:1;min-width:0}.script-indent{width:12px;flex-shrink:0}.script-enabled{color:#4caf50}.script-disabled{color:#888}.script-name{font-size:12px;color:var(--SmartThemeBodyColor);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:1}.script-buttons{display:flex;align-items:center;gap:2px;font-size:10px;color:#666;flex-shrink:0}.script-actions{display:flex;gap:4px;flex-shrink:0;opacity:0;transition:opacity .2s ease}.script-node:hover .script-actions{opacity:1}.toggle-btn{background:none;border:none;cursor:pointer;padding:2px 4px;border-radius:2px;color:#888;transition:all .2s ease;font-size:10px}.toggle-btn:hover{background:hsla(0,0%,100%,.1)}.toggle-btn.enabled{color:#4caf50}.folder-tree-node[style*=padding-left] .folder-header{position:relative}.folder-tree-node[style*=padding-left] .folder-header::before{content:"";position:absolute;left:-1px;top:50%;width:8px;height:1px;background:hsla(0,0%,100%,.1)}