.dialog-overlay{position:fixed;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,.5);backdrop-filter:blur(4px);display:flex;align-items:center;justify-content:center;z-index:10000;padding:20px}.dialog{background:var(--SmartThemeBlurTintColor);border:1px solid var(--SmartThemeBorderColor);border-radius:8px;box-shadow:0 8px 32px rgba(0,0,0,.4);max-width:500px;width:100%;max-height:80vh;display:flex;flex-direction:column;overflow:hidden}.dialog-header{display:flex;justify-content:space-between;align-items:center;padding:20px 24px 16px 24px;border-bottom:1px solid var(--SmartThemeBorderColor)}.dialog-title{margin:0;font-size:18px;font-weight:600;color:var(--SmartThemeEmColor)}.dialog-close-btn{background:none;border:none;color:#888;cursor:pointer;padding:4px;border-radius:4px;font-size:14px;transition:all .2s ease}.dialog-close-btn:hover{color:var(--SmartThemeEmColor);background:hsla(0,0%,100%,.1)}.dialog-body{flex:1;padding:20px 24px;overflow-y:auto}.dialog-message{display:flex;gap:16px;align-items:flex-start}.message-icon{flex-shrink:0;font-size:24px;color:var(--SmartThemeEmColor)}.message-text{flex:1;line-height:1.5;color:var(--SmartThemeBodyColor);font-size:14px}.dialog-footer{display:flex;justify-content:flex-end;gap:12px;padding:16px 24px 20px 24px;border-top:1px solid var(--SmartThemeBorderColor)}.dialog-btn{padding:8px 16px;border-radius:4px;font-size:14px;cursor:pointer;transition:all .2s ease;border:1px solid var(--SmartThemeBorderColor);background:none;color:var(--SmartThemeBodyColor)}.dialog-btn:hover{background:hsla(0,0%,100%,.1)}.dialog-btn-cancel{color:#888}.dialog-btn-cancel:hover{color:var(--SmartThemeBodyColor);border-color:var(--SmartThemeBodyColor)}.dialog-btn-confirm,.dialog-btn-primary{background:var(--SmartThemeQuoteColor);color:var(--SmartThemeEmColor);border-color:var(--SmartThemeEmColor)}.dialog-btn-confirm:hover,.dialog-btn-primary:hover{background:var(--SmartThemeEmColor);color:var(--SmartThemeQuoteColor)}.dialog-enter-active,.dialog-leave-active{transition:all .3s ease}.dialog-enter-from,.dialog-leave-to{opacity:0;transform:scale(0.9) translateY(-20px)}.dialog-body::-webkit-scrollbar{width:6px}.dialog-body::-webkit-scrollbar-track{background:rgba(0,0,0,.1)}.dialog-body::-webkit-scrollbar-thumb{background:hsla(0,0%,100%,.2);border-radius:3px}.dialog-body::-webkit-scrollbar-thumb:hover{background:hsla(0,0%,100%,.3)}